/****
 * Calc to return = CQP_TOTAL_EXPORTS_CIF_PERCENTAGE + CQP_TOTAL_EXPORTS_FOB_PERCENTAGE + CQP_TOTAL_EXPORTS_OI_PERCENTAGE
 * By Adriana Centellas
 */

function safeNumber(v) {
  if (typeof v !== "string" && typeof v !== "number") return 0;

  const normalized = String(v).replace(/,/g, "");
  const n = Number(normalized);

  return Number.isNaN(n) ? 0 : n;
}

return safeNumber(this.CQP_TOTAL_EXPORTS_CIF_PERCENTAGE) + safeNumber(this.CQP_TOTAL_EXPORTS_FOB_PERCENTAGE) + safeNumber(this.CQP_TOTAL_EXPORTS_OI_PERCENTAGE);

