 */

// Convert any value to a safe number
function safeNumber(v) {
  if (typeof v !== "string" && typeof v !== "number") return 0;

  const normalized = String(v).replace(/,/g, "");
  const n = Number(normalized);

  return Number.isNaN(n) ? 0 : n;
}

// Ensure numeric values
let annualExports = safeNumber(this.CQP_TOTAL_EXPORTS_ANNUAL_USD);
let historicalExports = safeNumber(this.CQP_TOTAL_EXPORTS_HISTORICAL);

// Main calculation
var returnVar = (historicalExports !== 0 && annualExports !== 0)
  ? ((annualExports / historicalExports) - 1) * 100
  : 0;


// Remove classes first
setTimeout(function () {
  const inputSelector = $('[selector="CQP_TOTAL_EXPORTS_VARIATION"] > div > input');
  inputSelector.removeClass('inputError inputOk');
}, 200);


// Only evaluate color if result is a valid number and not zero
if (!Number.isNaN(returnVar) && returnVar !== 0) {

  let valor = parseFloat(returnVar);

  setTimeout(function () {
    const inputSelector = $('[selector="CQP_TOTAL_EXPORTS_VARIATION"] > div > input');
    inputSelector.removeClass('inputError inputOk');

    if (valor < 0) {
      inputSelector.addClass('inputError'); // red
    } else if (valor > 0) {
      inputSelector.addClass('inputOk'); // green
    }

  }, 500);
}

return returnVar;

